onRecordDelete(c=>{if($os.getenv("ENVIRONMENT")!=="dev"){let o=c.record.get("repo"),e=c.record.get("name"),t=$os.getenv("RUNNER_URL");try{$os.exec("sudo","a2dissite",o,`${o}-le-ssl`).run()}catch{console.warn(`${o}-le-ssl could not be disabled`)}try{$os.exec("sudo","rm",`/etc/apache2/sites-available/${o}.conf`).run()}catch{console.warn(`${o} site config file could not be removed`)}try{$os.exec("sudo","rm",`/etc/apache2/sites-available/${o}-le-ssl.conf`).run()}catch{console.warn(`${o} site config file could not be removed`)}try{$os.exec("docker","stop",`${e}-container`).run()}catch{console.warn(`${e}-container could not be stopped`)}try{$os.exec("docker","rm",`${e}-container`).run()}catch{console.warn(`${e}-container could not be removed`)}try{$os.exec("docker","rmi",`${e}-image`).run()}catch{console.warn(`${e}-image could not be removed`)}try{$os.exec("certbot","delete","--cert-name",`${e}.${t}`,"--non-interactive").run()}catch{console.warn(`Certificate for ${e}.${t} could not be deleted`)}try{$os.exec("apache2ctl","restart").run()}catch{console.warn("apache2ctl could not be restarted")}}else console.log("Host metadata cannot be deleted in a dev environment.");c.next()},"hosts");
